package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// privateIPBlocks contains the list of private CIDR blocks to block
var privateIPBlocks []*net.IPNet

func init() {
	for _, cidr := range []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	} {
		_, block, _ := net.ParseCIDR(cidr)
		privateIPBlocks = append(privateIPBlocks, block)
	}
}

// isPrivateIP checks if an IP address belongs to a private or restricted network
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalMulticast() || ip.IsLinkLocalUnicast() {
		return true
	}

	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// safeTransport returns an http.Transport that prevents connections to private IPs
// This mitigates SSRF (Server-Side Request Forgery) attacks.
func safeTransport() *http.Transport {
	return &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve IPs
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			// Check all resolved IPs against blocklist
			var safeIP net.IP
			for _, ip := range ips {
				if isPrivateIP(ip) {
					continue
				}
				safeIP = ip
				break
			}

			if safeIP == nil {
				return nil, fmt.Errorf("access to local/private network denied")
			}

			// Dial the specific Safe IP to prevent DNS rebinding attacks
			// We reconstruct the address using the safe IP and original port
			addrWithSafeIP := net.JoinHostPort(safeIP.String(), port)
			return net.Dial(network, addrWithSafeIP)
		},
	}
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme (strictly http or https)
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Create a custom HTTP client with timeout and SSRF protection
	client := &http.Client{
		Timeout:   3 * time.Second,
		Transport: safeTransport(),
		// Prevent following redirects to avoid Open Redirect vulnerabilities leading to SSRF
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Send test request to webhook URL using GET method as required
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		// Differentiate between security blocks and network errors for logging (optional),
		// but return generic error to user.
		errMsg := fmt.Sprintf("Failed to reach webhook URL: %v", err)
		if strings.Contains(err.Error(), "access to local/private network denied") {
			errMsg = "Target URL is not allowed"
		}
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   errMsg,
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

