// WebhookConfig represents the JSON structure for the request body.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Global storage to simulate saving the configuration.
// In a real application, this would be a database.
var (
	savedWebhookURL string
	mutex           sync.RWMutex
)

// ConfigureWebhook handles the configuration of the webhook URL.
// It parses the request, validates the URL by sending a GET request with a 3-second timeout,
// and saves the configuration if successful.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	req := new(WebhookConfig)
	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the webhook URL by sending a GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to verify webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the remote server returned a success status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL returned non-success status code",
			"code":    resp.StatusCode,
		})
	}

	// Save the configuration (Thread-safe assignment)
	mutex.Lock()
	savedWebhookURL = req.WebhookURL
	mutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":      "success",
		"message":     "Webhook configuration saved successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the handler
