	client := &http.Client{
		Timeout:   5 * time.Second,
		Transport: transport,
		// Security: Disable redirects to prevent bypassing IP checks via external redirectors
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

