package main

import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// RequestBody defines the expected JSON structure for the configuration.
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// AppConfig simulates a storage backend for the application configuration.
type AppConfig struct {
	WebhookURL string
	mu         sync.RWMutex
}

var config AppConfig

// ConfigureWebhook handles the configuration of the webhook URL.
// It parses the request, validates the URL by sending a GET request with a 3-second timeout,
// and saves the configuration if successful.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var req RequestBody
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Create an HTTP client with the required 3-second timeout
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to verify webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the remote server returned a success status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned non-success status code",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration (Thread-safe update)
	config.mu.Lock()
	config.WebhookURL = req.WebhookURL
	config.mu.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and verified successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

