package main

import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the expected JSON request body.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Global storage to simulate saving the configuration.
// In a real application, this would be a database.
var (
	savedWebhookURL string
	mu              sync.Mutex
)

// ConfigureWebhook handles the configuration of a webhook URL.
// It validates the URL by sending a GET request with a 3-second timeout.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the request body
	var req WebhookConfig
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// 2. Validate the Webhook URL by sending a test request
	// Requirement: Set timeout to 3 seconds
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request to the provided URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":   "Failed to verify webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the remote server returned a success status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":       "Webhook URL returned unsuccessful status code",
			"status_code": resp.StatusCode,
		})
	}

	// 3. Save the configuration (Thread-safe mock storage)
	mu.Lock()
	savedWebhookURL = req.WebhookURL
	mu.Unlock()

	// 4. Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"message":     "Webhook configuration saved successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

