package main

import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the expected JSON body.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Global storage for the webhook URL (thread-safe for demonstration).
var (
	savedWebhookURL string
	mu              sync.RWMutex
)

// ConfigureWebhook handles the configuration and validation of a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	payload := new(WebhookConfig)
	if err := ctx.BodyParser(payload); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid JSON body",
			"error":   err.Error(),
		})
	}

	if payload.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Validate the Webhook URL by sending a GET request
	// Requirement: Set timeout to 3 seconds
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(payload.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL (unreachable or timeout)",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the remote server returned a success status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration (Thread-safe update)
	mu.Lock()
	savedWebhookURL = payload.WebhookURL
	mu.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configuration saved successfully",
		"data": fiber.Map{
			"webhook_url": payload.WebhookURL,
		},
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	fmt.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

