// isSafeIP checks if an IP address is safe to connect to (public internet).
// It blocks private, loopback, and link-local addresses to prevent SSRF.
func isSafeIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalMulticast() || ip.IsLinkLocalUnicast() || ip.IsUnspecified() {
		return false
	}

	// Check for private IP ranges (e.g., 10.x.x.x, 192.168.x.x, 172.16.x.x)
	// ip.IsPrivate() was added in Go 1.17
	if ip.IsPrivate() {
		return false
	}

	return true
}

