func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Create a custom Dialer to validate IPs before connecting (SSRF Protection)
	dialer := &net.Dialer{
		Timeout:   2 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	transport := &http.Transport{
		// Use DialContext to intercept the connection attempt
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve IPs
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			// Iterate through resolved IPs and validate them
			var targetIP net.IP
			for _, ip := range ips {
				if !isSafeIP(ip) {
					return nil, fmt.Errorf("connection to private/local IP %s is forbidden", ip.String())
				}
				// Select the first valid IPv4 if available, otherwise keep the first valid IP
				if targetIP == nil || (targetIP.To4() == nil && ip.To4() != nil) {
					targetIP = ip
				}
			}

			if targetIP == nil {
				return nil, fmt.Errorf("no valid IP addresses found for host")
			}

			// Connect to the validated IP address explicitly to prevent DNS rebinding
			safeAddr := net.JoinHostPort(targetIP.String(), port)
			return dialer.DialContext(ctx, network, safeAddr)
		},
		DisableKeepAlives: true,
	}

