)

// WebhookConfigRequest represents the expected JSON body.
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// AppState simulates a storage layer for the configuration.
type AppState struct {
	WebhookURL string
	mu         sync.Mutex
}

var state AppState

// ConfigureWebhook handles the configuration of the webhook URL.
// It parses the JSON body, validates the URL by sending a GET request
// with a 3-second timeout, and saves the configuration if successful.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// 2. Validate the Webhook URL by sending a test GET request
	// Requirement: Set the timeout to 3 seconds.
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		// This handles network errors, invalid URLs, or timeouts
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Optional: You might want to check resp.StatusCode here (e.g., ensure it's 200 OK),
	// but the requirement only specifies sending a test request.
	// We assume if we got a response, the URL is reachable.

	// 3. Save the configuration (Thread-safe update)
	state.mu.Lock()
	state.WebhookURL = req.WebhookURL
	state.mu.Unlock()

	// 4. Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":      "success",
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

