	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest represents the expected JSON body for configuration.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// In-memory storage for the configured webhook (simulating a database).
var savedWebhookURL string

// ConfigureWebhook handles the configuration and validation of a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the request body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid request body",
		})
	}

	// Basic validation check
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url field is required",
		})
	}

	// Validate the webhook URL by sending a test GET request.
	// Requirement: Set the timeout to 3 seconds.
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the endpoint returned a success status code (2xx).
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL returned non-success status code",
		})
	}

	// Save the configuration (Mock implementation)
	savedWebhookURL = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":      "success",
		"message":     "Webhook configured and verified successfully",
		"webhook_url": savedWebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

