package main

import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the expected JSON body.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Global storage to simulate saving the configuration.
// In a real application, this would likely be a database.
var (
	savedWebhookURL string
	mutex           sync.RWMutex
)

// ConfigureWebhook handles the configuration of the webhook.
// It parses the JSON body, validates the URL by sending a GET request
// with a 3-second timeout, and saves the configuration if successful.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid JSON body",
		})
	}

	// Basic validation
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Create an HTTP client with the required 3-second timeout
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the endpoint returned a success status code (2xx)
	// This logic can be adjusted based on specific requirements,
	// but generally, a webhook endpoint should return 200 OK.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL returned non-success status code",
			"code":    resp.StatusCode,
		})
	}

	// Save the configuration (Thread-safe)
	mutex.Lock()
	savedWebhookURL = config.WebhookURL
	mutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":      "success",
		"message":     "Webhook configured and verified successfully",
		"webhook_url": config.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

