)

// WebhookConfig represents the expected JSON request body.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Global storage to simulate saving the configuration.
// In a real application, this would likely be a database.
var (
	currentWebhookURL string
	configMutex       sync.RWMutex
)

// ConfigureWebhook handles the configuration and validation of the webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the request body
	payload := new(WebhookConfig)
	if err := ctx.BodyParser(payload); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid JSON body",
		})
	}

	if payload.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// 2. Validate the Webhook URL by sending a test GET request
	// Requirement: Set the timeout to 3 seconds.
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(payload.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Optional: Check if the remote server returned a success status code.
	// We assume a 2xx code indicates a valid endpoint.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned non-success status code",
			"status":  resp.StatusCode,
		})
	}

	// 3. Save the configuration (Thread-safe)
	configMutex.Lock()
	currentWebhookURL = payload.WebhookURL
	configMutex.Unlock()

	// 4. Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and verified successfully",
		"webhook_url": payload.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

