			}

			// Dial the specific validated IP to prevent DNS rebinding attacks.
			// JoinHostPort handles wrapping IPv6 addresses in brackets if necessary.
			return dialer.DialContext(ctx, network, net.JoinHostPort(safeIP.String(), port))
