package main

import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the expected JSON request body.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// In-memory storage to simulate saving the configuration.
var (
	savedWebhookURL string
	mu              sync.RWMutex
)

// ConfigureWebhook handles the configuration and validation of a webhook URL.
// It parses the JSON body, sends a test GET request with a 3-second timeout,
// and saves the configuration if successful.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid JSON body",
		})
	}

	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Create an HTTP client with the required 3-second timeout
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the remote server returned a success status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL returned non-success status code: " + resp.Status,
		})
	}

	// Save the configuration (Thread-safe)
	mu.Lock()
	savedWebhookURL = config.WebhookURL
	mu.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":      "success",
		"message":     "Webhook configured and validated successfully",
		"webhook_url": config.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

