// isSafeIP checks if an IP address is safe to connect to.
// It returns false for private, loopback, multicast, or link-local addresses.
func isSafeIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsMulticast() || ip.IsUnspecified() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return false
	}
	// IsPrivate covers RFC 1918 (IPv4 private) and RFC 4193 (IPv6 private)
