	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// SSRF Protection: Create a custom transport that validates the destination IP
	// and prevents DNS rebinding by resolving and dialing the specific IP.
	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve IPs
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			// Find the first safe IP
			var safeIP net.IP
			for _, ip := range ips {
				if isSafeIP(ip) {
					safeIP = ip
					break
				}
			}

			if safeIP == nil {
				return nil, fmt.Errorf("webhook URL resolves to a forbidden IP address")
			}

			// Dial the specific safe IP to prevent DNS rebinding
			dialAddr := net.JoinHostPort(safeIP.String(), port)
			dialer := &net.Dialer{
				Timeout:   3 * time.Second,
				KeepAlive: 30 * time.Second,
			}
			return dialer.DialContext(ctx, network, dialAddr)
		},
		DisableKeepAlives: true,
	}

